import{describe,it,expect,vi,beforeEach,afterEach}from"vitest";globalThis.window=globalThis.window||globalThis,window.ErrorHandler={log:vi.fn()};const origLocation=globalThis.location;describe("Logger (production mode)",()=>{let Logger;async function loadLogger(){const fs=await import("fs"),path=await import("path"),src=fs.readFileSync(path.resolve("./logger.js"),"utf8");return eval(src),window.Logger}beforeEach(()=>{vi.restoreAllMocks(),delete globalThis.location,globalThis.location={hostname:"app.auditcb360.com"},delete window.Logger,delete window.DEBUG_MODE}),afterEach(()=>{globalThis.location=origLocation}),it("should set DEBUG_MODE to false for non-localhost",async()=>{await loadLogger(),expect(window.DEBUG_MODE).toBe(!1)}),it("debug should NOT log when DEBUG_MODE is false",async()=>{const e=vi.spyOn(console,"log").mockImplementation(()=>{});Logger=await loadLogger(),Logger.debug("test message"),expect(e).not.toHaveBeenCalled(),e.mockRestore()}),it("log should NOT log when DEBUG_MODE is false",async()=>{const e=vi.spyOn(console,"log").mockImplementation(()=>{});Logger=await loadLogger(),Logger.log("test message"),expect(e).not.toHaveBeenCalled(),e.mockRestore()}),it("info should always log regardless of DEBUG_MODE",async()=>{const e=vi.spyOn(console,"info").mockImplementation(()=>{});Logger=await loadLogger(),Logger.info("info message"),expect(e).toHaveBeenCalledTimes(1),expect(e.mock.calls[0][0]).toContain("[INFO]"),e.mockRestore()}),it("info should support module-prefixed form",async()=>{const e=vi.spyOn(console,"info").mockImplementation(()=>{});Logger=await loadLogger(),Logger.info("MyModule","info message"),expect(e).toHaveBeenCalledTimes(1),expect(e.mock.calls[0][0]).toContain("[MyModule]"),e.mockRestore()}),it("warn should always log regardless of DEBUG_MODE",async()=>{const e=vi.spyOn(console,"warn").mockImplementation(()=>{});Logger=await loadLogger(),Logger.warn("warning message"),expect(e).toHaveBeenCalledTimes(1),expect(e.mock.calls[0][0]).toContain("[WARN]"),e.mockRestore()}),it("warn should support module-prefixed form",async()=>{const e=vi.spyOn(console,"warn").mockImplementation(()=>{});Logger=await loadLogger(),Logger.warn("MyModule","warning message"),expect(e).toHaveBeenCalledTimes(1),expect(e.mock.calls[0][0]).toContain("[MyModule]"),e.mockRestore()}),it("error should always log regardless of DEBUG_MODE",async()=>{const e=vi.spyOn(console,"error").mockImplementation(()=>{});Logger=await loadLogger(),Logger.error("error message"),expect(e).toHaveBeenCalledTimes(1),expect(e.mock.calls[0][0]).toContain("[ERROR]"),e.mockRestore()}),it("error should support module-prefixed form",async()=>{const e=vi.spyOn(console,"error").mockImplementation(()=>{});Logger=await loadLogger(),Logger.error("MyModule","error details"),expect(e).toHaveBeenCalledTimes(1),expect(e.mock.calls[0][0]).toContain("[MyModule]"),e.mockRestore()}),it("error should integrate with ErrorHandler when error object provided",async()=>{vi.spyOn(console,"error").mockImplementation(()=>{}),Logger=await loadLogger();const e=new Error("test error");Logger.error("TestModule","something failed",e),expect(window.ErrorHandler.log).toHaveBeenCalledWith(e,"TestModule"),vi.restoreAllMocks()}),it("error with single arg should pass it to ErrorHandler",async()=>{vi.spyOn(console,"error").mockImplementation(()=>{}),Logger=await loadLogger();const e=new Error("single arg error");Logger.error(e),expect(window.ErrorHandler.log).toHaveBeenCalledWith(e,"Unknown"),vi.restoreAllMocks()})}),describe("Logger (debug mode)",()=>{let Logger;async function loadLogger(){const fs=await import("fs"),path=await import("path"),src=fs.readFileSync(path.resolve("./logger.js"),"utf8");return eval(src),window.Logger}beforeEach(()=>{vi.restoreAllMocks(),delete globalThis.location,globalThis.location={hostname:"localhost"},delete window.Logger,delete window.DEBUG_MODE}),afterEach(()=>{globalThis.location=origLocation}),it("should set DEBUG_MODE to true for localhost",async()=>{const e=vi.spyOn(console,"log").mockImplementation(()=>{});await loadLogger(),expect(window.DEBUG_MODE).toBe(!0),e.mockRestore()}),it("debug should log when DEBUG_MODE is true (single arg)",async()=>{const e=vi.spyOn(console,"log").mockImplementation(()=>{});Logger=await loadLogger(),Logger.debug("debug message");const o=e.mock.calls.filter(e=>"string"==typeof e[0]&&e[0].includes("[DEBUG]"));expect(o.length).toBe(1),e.mockRestore()}),it("debug should log with module prefix (two args)",async()=>{const e=vi.spyOn(console,"log").mockImplementation(()=>{});Logger=await loadLogger(),Logger.debug("MyModule","debug info");const o=e.mock.calls.filter(e=>"string"==typeof e[0]&&e[0].includes("[MyModule]"));expect(o.length).toBe(1),e.mockRestore()}),it("debug should log with module prefix and data (three args)",async()=>{const e=vi.spyOn(console,"log").mockImplementation(()=>{});Logger=await loadLogger();const o={key:"value"};Logger.debug("MyModule","debug info",o);const t=e.mock.calls.filter(e=>"string"==typeof e[0]&&e[0].includes("[MyModule]"));expect(t.length).toBe(1),expect(t[0][2]).toBe(o),e.mockRestore()}),it("log should output in debug mode",async()=>{const e=vi.spyOn(console,"log").mockImplementation(()=>{});Logger=await loadLogger(),Logger.log("raw log message");const o=e.mock.calls.filter(e=>"raw log message"===e[0]);expect(o.length).toBe(1),e.mockRestore()})});